def detect_view_mode() -> str:
    """Detect dashboard layout without forcing the user to choose a landing page.

    Query override is useful during testing:
    - streamlit-url?view=desktop
    - streamlit-url?view=mobile
    """
    try:
        query_view = str(st.query_params.get("view", "")).strip().lower()
        if query_view in {"desktop", "mobile"}:
            return query_view.capitalize()
    except Exception:
        pass

    user_agent = ""
    try:
        user_agent = str(st.context.headers.get("user-agent", "")).lower()
    except Exception:
        user_agent = ""

    mobile_keywords = [
        "iphone", "android", "mobile", "phone", "blackberry",
        "opera mini", "windows phone", "iemobile", "ipod",
    ]
    tablet_keywords = ["ipad", "tablet"]

    if any(token in user_agent for token in mobile_keywords) and not any(token in user_agent for token in tablet_keywords):
        return "Mobile"
    return "Desktop"


VIEW_MODE = detect_view_mode()
IS_MOBILE_MODE = VIEW_MODE == "Mobile"
IS_TABLET_MODE = False
