def station_country_name(station: str) -> Optional[str]:
    key = normalize_key(station)
    if key in STATION_COUNTRY_BY_KEY:
        return STATION_COUNTRY_BY_KEY[key]
    if "BANGKOK" in key or "PHUKET" in key or "CHIANG" in key:
        return "Thailand"
    if "TOKYO" in key or "HANEDA" in key or "OSAKA" in key or "NAGOYA" in key:
        return "Japan"
    if "SEOUL" in key:
        return "South Korea"
    if "DUBAI" in key:
        return "United Arab Emirates"
    if "SYDNEY" in key or "MELBOURNE" in key or "PERTH" in key:
        return "Australia"
    return None


def weighted_mean_by_rsp(df: pd.DataFrame, value_col: str, weight_col: str = "RSP") -> float:
    values = pd.to_numeric(df.get(value_col, 0), errors="coerce").fillna(0)
    weights = pd.to_numeric(df.get(weight_col, 0), errors="coerce").fillna(0)
    if weights.sum() > 0:
        return float((values * weights).sum() / weights.sum())
    return float(values.mean()) if len(values) else 0.0


def expand_nationality_choropleth(nat_df: pd.DataFrame) -> pd.DataFrame:
    rows = []
    if nat_df.empty:
        return pd.DataFrame(columns=["Country", "ISO3", "Nationality Group", "Percent", "Count"])
    for _, row in nat_df.iterrows():
        group = str(row.get("Nationality Group", "")).strip()
        countries = NATIONALITY_CHOROPLETH_COUNTRIES.get(group, [])
        for country in countries:
            rows.append(
                {
                    "Country": country,
                    "ISO3": country_to_iso3(country),
                    "Nationality Group": group,
                    "Percent": float(row.get("Percent", 0) or 0),
                    "Count": float(row.get("Count", 0) or 0),
                }
            )
    return pd.DataFrame(rows)


def _request_scroll_to_top() -> None:
    """Mark that the next Streamlit rerun should force the main document to the top."""
    st.session_state["_tcss_force_scroll_to_top"] = True


def render_touchpoint_tree(container, option_labels: List[str], default_labels: Optional[List[str]] = None) -> List[str]:
    """Render a reliable single service-touchpoint selector inside the sidebar expander.

    User-facing "Overall" maps to the internal All Touchpoints view.
    Returns [] for Overall or a one-item list for one selected touchpoint.

    Important implementation detail:
    Use the expander object itself for child widgets. Calling st.radio() or
    container.radio() inside a `with container.expander(...)` block can render
    widgets outside the details container in some Streamlit versions/themes,
    which makes the expander appear not to collapse and can make radio clicks
    unreliable.
    """
    container.markdown("### Select Touchpoint")
    options = ["Overall"] + option_labels
    default_value = "Overall"
    if default_labels and len(default_labels) == 1:
        incoming_default = default_labels[0]
        if incoming_default == "All Touchpoints":
            incoming_default = "Overall"
        if incoming_default in options:
            default_value = incoming_default

    exp = container.expander("Service Touchpoint", expanded=True)
    selected = exp.radio(
        "View",
        options=options,
        index=options.index(default_value),
        key=f"single_touchpoint_{VIEW_MODE}",
        label_visibility="collapsed",
        on_change=_request_scroll_to_top,
    )
    exp.markdown(
        f"<div class='touchpoint-selected-pill'><span>Selected</span><b>{html.escape(str(selected))}</b></div>",
        unsafe_allow_html=True,
    )
    return [] if selected == "Overall" else [selected]



def render_touchpoint_selector(container, options: List[str], default_index: int = 0) -> str:
    """Backward-compatible single select helper, kept for old calls."""
    container.markdown("### Touchpoint")
    with container.expander("▼ Select Touchpoint", expanded=True):
        return st.selectbox(
            "Touchpoint",
            options=options,
            index=default_index,
            key=f"touchpoint_select_{VIEW_MODE}",
            label_visibility="collapsed",
        )


def find_first_column(df: pd.DataFrame, candidates: List[str]) -> Optional[str]:
    if df.empty:
        return None
    lookup = {normalize_key(col): col for col in df.columns}
    for cand in candidates:
        key = normalize_key(cand)
        if key in lookup:
            return lookup[key]
    for col in df.columns:
        key = normalize_key(col)
        for cand in candidates:
            if normalize_key(cand) in key:
                return col
    return None

def render_light_html_table(df: pd.DataFrame, max_height: int = 420, column_config: Optional[dict] = None):
    """Render a light, sortable data grid.

    st.dataframe keeps column-header sorting available. Keep numeric columns numeric and use
    column_config formatting instead of converting values to strings; otherwise sorting will
    become lexical rather than numeric.
    """
    if df.empty:
        st.info("No data available.")
        return

    safe_df = df.copy()
    st.markdown(
        "<div class='table-caption-note'>Click any column header to sort. Scroll horizontally for long tables.</div>",
        unsafe_allow_html=True,
    )
    dataframe_kwargs = {
        "use_container_width": True,
        "height": int(max_height) if max_height else 420,
        "hide_index": True,
    }
    if column_config:
        dataframe_kwargs["column_config"] = column_config
    st.dataframe(safe_df, **dataframe_kwargs)

