def complaint_norm(value: object) -> str:
    return re.sub(r"[^a-z0-9]+", "", str(value or "").strip().lower())


def is_blank_like(value: object) -> bool:
    if value is None:
        return True
    if isinstance(value, float) and pd.isna(value):
        return True
    return clean_text(value) == ""


def is_flight_header(value: object) -> bool:
    key = complaint_norm(value)
    return key in {"flight", "fltno", "flt", "flightno", "flightnumber"}


def is_date_header(value: object) -> bool:
    return complaint_norm(value) in {"date", "flightdate"}


def is_ac_header(value: object) -> bool:
    key = complaint_norm(value)
    return key in {"ac", "actype", "aircraft", "aircrafttype", "aircraftcode"}


def is_from_header(value: object) -> bool:
    key = complaint_norm(value)
    return key in {"from", "form", "arrivedto", "arrivalto", "destination", "to", "station"}


def is_metadata_header(value: object) -> bool:
    key = complaint_norm(value)
    return key in {
        "", "no", "number", "flight", "fltno", "flt", "flightno", "flightnumber",
        "date", "flightdate", "ac", "actype", "aircraft", "aircrafttype",
        "from", "form", "arrivedto", "arrivalto", "seat", "seatno", "class",
        "first", "firstclass", "business", "businessclass", "economy", "economyclass",
        "dc", "dom", "japan", "australia", "eu", "asia", "clmv", "indpak", "india", "pakistan",
    }


def clean_flight_no(value: object) -> str:
    txt = clean_text(value).upper().replace(" ", "")
    txt = re.sub(r"[^A-Z0-9]", "", txt)
    if not txt:
        return ""
    # Most records are TG flight numbers. Keep other airline-like values if the source uses them.
    match = re.search(r"([A-Z]{2}\d{2,4}[A-Z]?)", txt)
    return match.group(1) if match else txt


def looks_like_flight(value: object) -> bool:
    txt = clean_flight_no(value)
    if not txt:
        return False
    if txt in {"FLIGHT", "FLTNO", "DATE", "FROM"}:
        return False
    return bool(re.match(r"^[A-Z]{2}\d{2,4}[A-Z]?$", txt))


def parse_excel_date(value: object) -> pd.Timestamp:
    if value is None or (isinstance(value, float) and pd.isna(value)):
        return pd.NaT
    if isinstance(value, pd.Timestamp):
        return value
    parsed = pd.to_datetime(value, errors="coerce")
    if pd.notna(parsed):
        return parsed
    if isinstance(value, (int, float)) and not pd.isna(value):
        try:
            return pd.to_datetime("1899-12-30") + pd.to_timedelta(float(value), unit="D")
        except Exception:
            return pd.NaT
    return pd.NaT


def parse_month_from_complaint_file(file_path: Path) -> Optional[str]:
    text_value = file_path.stem
    # Accept patterns such as Complaint 202505, 2025-05, MAY 2025.
    match = re.search(r"(20\d{2})[\-_ ]?(0[1-9]|1[0-2])", text_value)
    if match:
        return f"{match.group(1)}-{match.group(2)}"
    for mon_name, mon_num in MONTH_NAME_TO_NUM.items():
        if re.search(mon_name, text_value, flags=re.IGNORECASE):
            year_match = re.search(r"(20\d{2})", text_value)
            if year_match:
                return f"{year_match.group(1)}-{mon_num:02d}"
    return None


def infer_complaint_main_topic(sheet_name: str) -> str:
    key = sheet_name.lower().strip()
    compact = complaint_norm(sheet_name)
    if "check" in key:
        return "Check-in"
    if "lounge" in key:
        return "Lounge"
    if "boarding" in key:
        return "Boarding"
    if "beverage" in key:
        return "In-flight Beverage"
    # All Inflight meal sheets, including DC_DOM / DC_Other Asia / DC_CLMV / DC_IND & PAK,
    # are intentionally consolidated into the same executive-facing main topic.
    if "meal" in key or "inflightmealdc" in compact:
        return "In-flight Meal"
    if "cabin cleanliness" in key:
        return "Cabin Cleanliness"
    if "arrival" in key or "baggage" in key:
        return "Arrival & Baggage"
    if "irregular" in key:
        return "Irregularity"
    return canonical_topic(sheet_name)


def should_extract_complaint_sheet(sheet_name: str) -> bool:
    key = sheet_name.lower().strip()
    compact = complaint_norm(sheet_name)
    required_norm = {complaint_norm(x) for x in COMPLAINT_REQUIRED_RAW_SHEETS}
    if complaint_norm(sheet_name) in required_norm:
        return True
    if any(token in key for token in COMPLAINT_MEAL_SHEET_KEYWORDS):
        return True
    # Defensive support for new DC sheet naming conventions.
    return compact.startswith("inflightmealdc") or compact.startswith("inflightmeal")


def find_complaint_topic_column(row_values: List[object], flight_col: int) -> Optional[int]:
    search_end = min(len(row_values), flight_col + 10)
    from_col = None
    ac_col = None
    for idx in range(flight_col + 1, search_end):
        val = row_values[idx]
        if is_from_header(val):
            from_col = idx
        if is_ac_header(val):
            ac_col = idx
    start_idx = (from_col + 1) if from_col is not None else ((ac_col + 1) if ac_col is not None else flight_col + 1)
    for idx in range(start_idx, search_end):
        val = row_values[idx]
        if is_blank_like(val) or is_metadata_header(val):
            continue
        return idx
    # Fallback for classic Flight-Date-AC-From-Topic layout.
    fallback = flight_col + 4
    return fallback if fallback < len(row_values) else None


def detect_complaint_block(row_values: List[object], flight_col: int) -> Optional[Dict[str, int]]:
    search_end = min(len(row_values), flight_col + 10)
    date_col = None
    ac_col = None
    from_col = None
    for idx in range(flight_col + 1, search_end):
        val = row_values[idx]
        if date_col is None and is_date_header(val):
            date_col = idx
        elif ac_col is None and is_ac_header(val):
            ac_col = idx
        elif from_col is None and is_from_header(val):
            from_col = idx
    topic_col = find_complaint_topic_column(row_values, flight_col)
    if topic_col is None:
        return None
    return {
        "flight_col": flight_col,
        "date_col": date_col if date_col is not None else flight_col + 1,
        "ac_col": ac_col if ac_col is not None else flight_col + 2,
        "from_col": from_col if from_col is not None else flight_col + 3,
        "topic_col": topic_col,
    }


def extract_complaint_sheet(raw_sheet: pd.DataFrame, sheet_name: str, source_file: Path, default_month: Optional[str]) -> pd.DataFrame:
    records: List[Dict[str, object]] = []
    if raw_sheet.empty:
        return pd.DataFrame(columns=COMPLAINT_OUTPUT_COLUMNS)

    main_topic = infer_complaint_main_topic(sheet_name)
    raw_sheet = raw_sheet.copy()
    header_rows: List[Tuple[int, Dict[str, int], str]] = []

    for row_idx in range(len(raw_sheet)):
        row_values = raw_sheet.iloc[row_idx].tolist()
        for col_idx, value in enumerate(row_values):
            if not is_flight_header(value):
                continue
            block = detect_complaint_block(row_values, col_idx)
            if block is None:
                continue
            topic_name = clean_text(row_values[block["topic_col"]])
            if not topic_name or is_metadata_header(topic_name):
                continue
            header_rows.append((row_idx, block, topic_name))

    for header_idx, block, topic_name in header_rows:
        for data_idx in range(header_idx + 1, len(raw_sheet)):
            row_values = raw_sheet.iloc[data_idx].tolist()
            # Stop only when the same column becomes a new Flight header. Other topic blocks can continue lower down.
            if block["flight_col"] < len(row_values) and is_flight_header(row_values[block["flight_col"]]):
                break
            try:
                flight_value = row_values[block["flight_col"]]
            except Exception:
                continue
            if not looks_like_flight(flight_value):
                continue
            comment_value = row_values[block["topic_col"]] if block["topic_col"] < len(row_values) else None
            comment_text = clean_text(comment_value)
            if len(comment_text) < 2 or is_metadata_header(comment_text):
                continue
            date_value = row_values[block["date_col"]] if block["date_col"] < len(row_values) else None
            date_parsed = parse_excel_date(date_value)
            month_value = pd.to_datetime(date_parsed).strftime("%Y-%m") if pd.notna(date_parsed) else default_month
            ac_value = row_values[block["ac_col"]] if block["ac_col"] < len(row_values) else ""
            from_value = row_values[block["from_col"]] if block["from_col"] < len(row_values) else ""
            records.append(
                {
                    "Main Topic": display_topic(main_topic),
                    "Topic": clean_text(topic_name),
                    "FLIGHT": clean_flight_no(flight_value),
                    "DATE": date_parsed.to_pydatetime() if pd.notna(date_parsed) else None,
                    "A/C TYPE": clean_text(ac_value),
                    "FROM": clean_text(from_value),
                    "comment (text)": comment_text,
                    "Month": month_value,
                    "Source File": source_file.name,
                    "Source Sheet": sheet_name,
                }
            )

    out = pd.DataFrame(records)
    if out.empty:
        return pd.DataFrame(columns=COMPLAINT_OUTPUT_COLUMNS + ["Month", "Source File", "Source Sheet"])
    out = out.drop_duplicates(["Main Topic", "Topic", "FLIGHT", "DATE", "comment (text)"], keep="first")
    out["Topic"] = out["Topic"].replace({"nan": ""})
    return out.reset_index(drop=True)


def extract_complaint_workbook(file_path: Path) -> pd.DataFrame:
    default_month = parse_month_from_complaint_file(file_path)
    try:
        excel_file = pd.ExcelFile(file_path, engine="openpyxl")
    except Exception as exc:
        raise RuntimeError(f"Cannot open {file_path.name}: {exc}") from exc

    frames = []
    for sheet_name in excel_file.sheet_names:
        if not should_extract_complaint_sheet(sheet_name):
            continue
        try:
            raw_sheet = pd.read_excel(file_path, sheet_name=sheet_name, header=None, dtype=object, engine="openpyxl")
        except Exception:
            continue
        part = extract_complaint_sheet(raw_sheet, sheet_name, file_path, default_month)
        if not part.empty:
            frames.append(part)
    if not frames:
        return pd.DataFrame(columns=COMPLAINT_OUTPUT_COLUMNS + ["Month", "Source File", "Source Sheet"])
    return pd.concat(frames, ignore_index=True)


def validate_complaint_detail(detail_df: pd.DataFrame) -> pd.DataFrame:
    checks = []
    total_rows = len(detail_df)
    checks.append({"Check": "Total extracted rows", "Result": total_rows, "Status": "OK" if total_rows > 0 else "Warning"})
    for col in COMPLAINT_OUTPUT_COLUMNS:
        missing = int(detail_df[col].isna().sum()) if col in detail_df.columns else total_rows
        blank = int((detail_df[col].astype(str).str.strip() == "").sum()) if col in detail_df.columns else total_rows
        checks.append({"Check": f"Missing / blank {col}", "Result": missing + blank, "Status": "OK" if missing + blank == 0 else "Review"})
    if not detail_df.empty and set(["Main Topic", "Topic", "FLIGHT", "DATE", "comment (text)"]).issubset(detail_df.columns):
        duplicate_count = int(detail_df.duplicated(["Main Topic", "Topic", "FLIGHT", "DATE", "comment (text)"]).sum())
    else:
        duplicate_count = 0
    checks.append({"Check": "Duplicate complaint records", "Result": duplicate_count, "Status": "OK" if duplicate_count == 0 else "Review"})
    return pd.DataFrame(checks)


def build_summary_complaint_from_raw_folder(raw_folder: str, output_file: str = COMPLAINT_DETAIL_OUTPUT_DEFAULT) -> Tuple[pd.DataFrame, pd.DataFrame, Path]:
    raw_path = Path(raw_folder).expanduser()
    if not raw_path.is_absolute():
        # Prefer a folder placed next to app.py; fallback to current working directory.
        app_dir = Path(__file__).resolve().parent
        app_candidate = app_dir / raw_path
        cwd_candidate = Path.cwd() / raw_path
        raw_path = app_candidate if app_candidate.exists() else cwd_candidate
    if not raw_path.exists() or not raw_path.is_dir():
        raise FileNotFoundError(f"Raw complaint folder not found: {raw_path}")

    files = sorted(list(raw_path.glob("*.xlsx")) + list(raw_path.glob("*.xlsm")) + list(raw_path.glob("*.xls")))
    files = [f for f in files if not f.name.startswith("~$")]
    if not files:
        raise FileNotFoundError(f"No Excel complaint files found in: {raw_path}")

    frames = []
    errors = []
    for file_path in files:
        try:
            part = extract_complaint_workbook(file_path)
            if not part.empty:
                frames.append(part)
        except Exception as exc:
            errors.append({"File": file_path.name, "Error": str(exc)})

    detail = pd.concat(frames, ignore_index=True) if frames else pd.DataFrame(columns=COMPLAINT_OUTPUT_COLUMNS + ["Month", "Source File", "Source Sheet"])
    if not detail.empty:
        detail = detail.drop_duplicates(["Main Topic", "Topic", "FLIGHT", "DATE", "comment (text)"], keep="first")
        detail["DATE"] = pd.to_datetime(detail["DATE"], errors="coerce")
        detail["Month"] = detail["DATE"].dt.strftime("%Y-%m").fillna(detail.get("Month", ""))
        detail = detail.sort_values(["Month", "Main Topic", "Topic", "FLIGHT"], na_position="last")

    validation_df = validate_complaint_detail(detail)
    if errors:
        validation_df = pd.concat([validation_df, pd.DataFrame([{"Check": f"File error: {x['File']}", "Result": x["Error"], "Status": "Warning"} for x in errors])], ignore_index=True)

    summary_for_trend = pd.DataFrame(columns=["TCSS Topic", "Complaint Topic"])
    if not detail.empty:
        trend = detail.copy()
        trend["Month Label"] = pd.to_datetime(trend["Month"] + "-01", errors="coerce").dt.strftime("%b %Y")
        summary_for_trend = (
            trend.groupby(["Main Topic", "Topic", "Month Label"], as_index=False)
            .size()
            .rename(columns={"size": "Count"})
            .pivot_table(index=["Main Topic", "Topic"], columns="Month Label", values="Count", aggfunc="sum", fill_value=0)
            .reset_index()
            .rename(columns={"Main Topic": "TCSS Topic", "Topic": "Complaint Topic"})
        )

    output_path = Path(output_file).expanduser()
    if not output_path.is_absolute():
        # Write next to app.py so Streamlit can find it consistently even when launched from another cwd.
        output_path = Path(__file__).resolve().parent / output_path

    existing_commendation = None
    if output_path.exists():
        try:
            existing_commendation = pd.read_excel(output_path, sheet_name="Commendation", engine="openpyxl")
        except Exception:
            existing_commendation = None

    with pd.ExcelWriter(output_path, engine="openpyxl", mode="w") as writer:
        summary_for_trend.to_excel(writer, index=False, sheet_name="Summary")
        detail[COMPLAINT_OUTPUT_COLUMNS + ["Month", "Source File", "Source Sheet"]].to_excel(writer, index=False, sheet_name="Complaint Detail")
        validation_df.to_excel(writer, index=False, sheet_name="Data Quality")
        if existing_commendation is not None and not existing_commendation.empty:
            existing_commendation.to_excel(writer, index=False, sheet_name="Commendation")

    return detail, validation_df, output_path


def resolve_complaint_raw_folder(raw_folder: str = COMPLAINT_RAW_FOLDER_DEFAULT) -> Optional[Path]:
    """Return the Complaint_Raw folder if it exists next to app.py or in cwd."""
    folder = Path(raw_folder).expanduser()
    candidates = [folder] if folder.is_absolute() else [Path(__file__).resolve().parent / folder, Path.cwd() / folder]
    for candidate in candidates:
        if candidate.exists() and candidate.is_dir():
            return candidate
    return None


def newest_mtime(paths: List[Path]) -> float:
    mtimes = []
    for p in paths:
        try:
            mtimes.append(p.stat().st_mtime)
        except Exception:
            continue
    return max(mtimes) if mtimes else 0.0


def ensure_summary_complaint_detail_file(
    raw_folder: str = COMPLAINT_RAW_FOLDER_DEFAULT,
    output_file: str = COMPLAINT_DETAIL_OUTPUT_DEFAULT,
) -> Tuple[Optional[Path], Optional[str]]:
    """Auto-build Summary Complaint Detail.xlsx from Complaint_Raw when possible.

    This intentionally runs without a sidebar button. If the file already exists and is newer than
    all raw complaint files, it is reused. The dashboard remains usable even when the raw folder is
    missing; in that case it simply falls back to existing detail files if available.
    """
    raw_path = resolve_complaint_raw_folder(raw_folder)
    output_path = Path(__file__).resolve().parent / output_file

    if raw_path is None:
        return (output_path if output_path.exists() else None), None

    raw_files = sorted([p for p in list(raw_path.glob("*.xlsx")) + list(raw_path.glob("*.xlsm")) + list(raw_path.glob("*.xls")) if not p.name.startswith("~$")])
    if not raw_files:
        return (output_path if output_path.exists() else None), f"Complaint_Raw folder found but no Excel files are available: {raw_path}"

    try:
        output_is_current = output_path.exists() and output_path.stat().st_mtime >= newest_mtime(raw_files)
        if not output_is_current:
            detail, validation, built_path = build_summary_complaint_from_raw_folder(str(raw_path), str(output_path))
            status_msg = f"Created {built_path.name} from {len(raw_files):,} raw complaint files with {len(detail):,} rows."
            return built_path, status_msg
        return output_path, None
    except Exception as exc:
        return (output_path if output_path.exists() else None), f"Cannot auto-build {output_file}: {exc}"


def get_complaint_detail_signature() -> Tuple[Tuple[object, ...], Optional[str]]:
    """Build/reuse complaint-detail Excel and return a cache-busting file signature."""
    detail_path, status = ensure_summary_complaint_detail_file()
    raw_path = resolve_complaint_raw_folder()
    raw_files = []
    if raw_path is not None:
        raw_files = sorted([p for p in list(raw_path.glob("*.xlsx")) + list(raw_path.glob("*.xlsm")) + list(raw_path.glob("*.xls")) if not p.name.startswith("~$")])

    raw_signature = tuple((p.name, round(p.stat().st_mtime, 3), p.stat().st_size) for p in raw_files if p.exists())
    output_signature = (
        str(detail_path) if detail_path is not None else "",
        round(detail_path.stat().st_mtime, 3) if detail_path is not None and detail_path.exists() else 0,
        detail_path.stat().st_size if detail_path is not None and detail_path.exists() else 0,
    )
    return (output_signature, raw_signature), status


@st.cache_data(show_spinner=False)
def load_complaint_detail_data(signature: Optional[Tuple[object, ...]] = None) -> pd.DataFrame:
    auto_path, _auto_status = ensure_summary_complaint_detail_file()
    possible_names = [
        COMPLAINT_DETAIL_OUTPUT_DEFAULT,
        "Summary_Complaint_Detail.xlsx",
        "summary_complaint_detail.xlsx",
        # Backward compatibility: older versions stored detail inside Summary Complaint.xlsx.
        "Summary Complaint.xlsx",
        "Summary_Complaint.xlsx",
        "summary_complaint.xlsx",
    ]
    path = auto_path if auto_path is not None and auto_path.exists() else None
    if path is None:
        for name in possible_names:
            path = get_data_file_path(name)
            if path is not None:
                break
    if path is None:
        return pd.DataFrame(columns=COMPLAINT_OUTPUT_COLUMNS + ["Month", "Topic Canonical"])

    raw = pd.DataFrame()
    for sheet_name in COMPLAINT_DETAIL_SHEET_NAMES:
        try:
            raw = pd.read_excel(path, sheet_name=sheet_name, engine="openpyxl")
            if not raw.empty:
                break
        except Exception:
            continue
    if raw.empty:
        return pd.DataFrame(columns=COMPLAINT_OUTPUT_COLUMNS + ["Month", "Topic Canonical"])

    raw.columns = [clean_text(c) for c in raw.columns]
    mapping_candidates = {
        "Main Topic": ["Main Topic", "Touchpoint", "TCSS Topic", "Topic Group", "Service Touchpoint"],
        "Topic": ["Topic", "Complaint Topic", "Sub Topic", "Category", "Issue Topic"],
        "FLIGHT": ["FLIGHT", "Flight", "Flt.No.", "Flt No", "Flight No", "Flight Number"],
        "DATE": ["DATE", "Date", "Flight Date"],
        "A/C TYPE": ["A/C TYPE", "A/C", "AC", "Aircraft", "Aircraft Type", "A/C Type"],
        "FROM": ["FROM", "From", "Form", "Arrived to", "Station", "Origin"],
        "comment (text)": ["comment (text)", "Comment", "Comments", "Complaint", "Complaint Text", "Text", "Verbatim"],
    }
    renamed = {}
    norm_to_col = {complaint_norm(col): col for col in raw.columns}
    for target, candidates in mapping_candidates.items():
        source_col = None
        for cand in candidates:
            if complaint_norm(cand) in norm_to_col:
                source_col = norm_to_col[complaint_norm(cand)]
                break
        if source_col is None:
            for col in raw.columns:
                if any(complaint_norm(cand) in complaint_norm(col) for cand in candidates):
                    source_col = col
                    break
        if source_col is not None:
            renamed[source_col] = target
    raw = raw.rename(columns=renamed)
    for col in COMPLAINT_OUTPUT_COLUMNS:
        if col not in raw.columns:
            raw[col] = ""
    passthrough_month = raw["Month"].copy() if "Month" in raw.columns else pd.Series([""] * len(raw), index=raw.index)
    raw = raw[COMPLAINT_OUTPUT_COLUMNS].copy()
    raw["FLIGHT"] = raw["FLIGHT"].apply(clean_flight_no)
    raw["DATE"] = pd.to_datetime(raw["DATE"], errors="coerce")
    raw["Month"] = raw["DATE"].dt.strftime("%Y-%m")
    raw["Month"] = raw["Month"].fillna(passthrough_month.astype(str).str.slice(0, 7))
    raw["Main Topic"] = raw["Main Topic"].apply(clean_text)
    raw["Topic"] = raw["Topic"].apply(clean_text)
    raw["Topic Canonical"] = raw["Main Topic"].apply(canonical_topic)
    lavatory_mask = raw["Topic"].str.contains("lavatory|toilet|amenity", case=False, na=False)
    raw.loc[lavatory_mask, "Topic Canonical"] = "Lavatory Cleanliness"
    raw["comment (text)"] = raw["comment (text)"].apply(clean_text)
    raw = raw[(raw["FLIGHT"] != "") & (raw["comment (text)"] != "")].copy()
    raw = raw.drop_duplicates(["Main Topic", "Topic", "FLIGHT", "DATE", "comment (text)"], keep="first")
    return raw.reset_index(drop=True)




