CLASS_HEADER_KEYS = {
    "first", "firstclass", "business", "businessclass", "economy", "economyclass",
    "economyplus", "premiumeconomy", "dc", "dom", "japan", "asia", "australia", "eu",
    "pvgingoicn", "bkk", "clmv", "indpak", "india", "pakistan", "australia", "firstclass"
}


def topic_similarity(a: str, b: str) -> float:
    return SequenceMatcher(None, complaint_norm(a), complaint_norm(b)).ratio()


def has_alpha_or_thai(value: object) -> bool:
    text_value = clean_text(value)
    return bool(re.search(r"[A-Za-zก-๙]", text_value))


def is_numeric_like(value: object) -> bool:
    text_value = clean_text(value).replace(",", "")
    return bool(re.fullmatch(r"[-+]?\d+(?:\.\d+)?", text_value))


def is_valid_complaint_topic_header(value: object) -> bool:
    text_value = clean_text(value)
    key = complaint_norm(text_value)
    if not text_value or len(text_value) < 3:
        return False
    if key in CLASS_HEADER_KEYS:
        return False
    if is_numeric_like(text_value) or looks_like_flight(text_value):
        return False
    if is_metadata_header(text_value) or is_date_header(text_value) or is_from_header(text_value) or is_ac_header(text_value):
        return False
    return has_alpha_or_thai(text_value)


def infer_complaint_main_topic(sheet_name: str) -> str:
    key = str(sheet_name or "").lower().strip()
    compact = complaint_norm(sheet_name)
    if "arrival" in key or "baggage" in key:
        return "Arrival & Baggage Handling"
    if "cabin cleanliness" in key or compact.startswith("cabincleanliness"):
        return "Cabin Cleanliness"
    if "check" in key:
        return "Check-in"
    if "beverage" in key:
        return "In-flight Beverage"
    if "meal" in key or compact.startswith("inflightmealdc") or compact.startswith("inflightmeal"):
        return "Inflight Meal (DC double catering)"
    if "irregular" in key:
        return "Irregularity Handling"
    if "lounge" in key:
        return "Lounge"
    if "boarding" in key:
        return "Boarding"
    if "lavatory" in key or "toilet" in key:
        return "Lavatory Dirty"
    return display_topic(canonical_topic(sheet_name))


def should_extract_complaint_sheet(sheet_name: str) -> bool:
    key = str(sheet_name or "").lower().strip()
    compact = complaint_norm(sheet_name)
    required_norm = {complaint_norm(x) for x in COMPLAINT_REQUIRED_RAW_SHEETS}
    if compact in required_norm:
        return True
    if "detail" not in key and not compact.startswith("inflightmeal"):
        # Most complaint detail tabs include Details. Inflight meal tabs vary by region/DC naming.
        return False
    sheet_main = infer_complaint_main_topic(sheet_name)
    if sheet_main in COMPLAINT_TOPIC_TAXONOMY:
        return True
    return compact.startswith("inflightmealdc") or compact.startswith("inflightmeal")


def map_complaint_topic(main_topic: str, raw_topic: object) -> Tuple[str, str]:
    raw_text = clean_text(raw_topic)
    raw_key = complaint_norm(raw_text)
    main_topic = clean_text(main_topic)

    # Follow the approved taxonomy: Commendation is only kept where the taxonomy explicitly includes it.
    if "commend" in raw_text.lower() and "Commendation" not in COMPLAINT_TOPIC_TAXONOMY.get(main_topic, []):
        return main_topic, ""

    # First pass: deterministic keyword rules.
    for rule_main, canonical_label, keywords in COMPLAINT_TOPIC_RULES:
        if rule_main != main_topic and not (main_topic == "Cabin Cleanliness" and rule_main == "Lavatory Dirty"):
            continue
        if any(kw.lower() in raw_text.lower() or complaint_norm(kw) in raw_key for kw in keywords):
            if rule_main == "Lavatory Dirty":
                return "Lavatory Dirty", canonical_label
            return main_topic, canonical_label

    # Second pass: fuzzy match within the topic taxonomy.
    candidate_topics = COMPLAINT_TOPIC_TAXONOMY.get(main_topic, [])
    if main_topic == "Cabin Cleanliness":
        candidate_topics = candidate_topics + COMPLAINT_TOPIC_TAXONOMY.get("Lavatory Dirty", [])
    if candidate_topics:
        scored = [(topic_similarity(raw_text, candidate), candidate) for candidate in candidate_topics]
        score, best = max(scored, key=lambda x: x[0])
        if score >= 0.55:
            if best == "Lavatory Dirty":
                return "Lavatory Dirty", best
            return main_topic, best

    # Conservative fallback: keep a clean but unmapped topic rather than losing a valid record.
    return main_topic, raw_text[:140]


def parse_excel_date(value: object) -> pd.Timestamp:
    """Parse Excel dates without turning Excel serial numbers into 1970 timestamps."""
    if value is None or (isinstance(value, float) and pd.isna(value)):
        return pd.NaT
    if isinstance(value, pd.Timestamp):
        return value
    if hasattr(value, "year") and hasattr(value, "month") and hasattr(value, "day"):
        try:
            return pd.Timestamp(value)
        except Exception:
            pass
    if isinstance(value, (int, float)) and not pd.isna(value):
        # Excel serial dates for contemporary TCSS files usually sit around 45,000.
        # Parse numeric values before pd.to_datetime, otherwise pandas treats them as ns from 1970.
        if 20000 <= float(value) <= 80000:
            try:
                return pd.to_datetime("1899-12-30") + pd.to_timedelta(float(value), unit="D")
            except Exception:
                return pd.NaT
        return pd.NaT
    parsed = pd.to_datetime(value, errors="coerce")
    if pd.notna(parsed) and 1990 <= parsed.year <= 2100:
        return parsed
    return pd.NaT


def find_complaint_topic_column(row_values: List[object], flight_col: int) -> Optional[int]:
    # Complaint workbooks have repeated horizontal blocks:
    # [No.] [Flight] [Date] [A/C] [Seat optional] [From] [Topic Header]
    # The topic is the first valid non-metadata header to the right of From, usually within 8 columns.
    search_end = min(len(row_values), flight_col + 12)
    from_col = None
    for idx in range(flight_col + 1, search_end):
        if is_from_header(row_values[idx]):
            from_col = idx
    start_idx = (from_col + 1) if from_col is not None else flight_col + 3
    for idx in range(start_idx, search_end):
        if is_valid_complaint_topic_header(row_values[idx]):
            return idx
    return None


def detect_complaint_block(row_values: List[object], flight_col: int) -> Optional[Dict[str, int]]:
    search_end = min(len(row_values), flight_col + 12)
    date_col = None
    ac_col = None
    from_col = None
    for idx in range(flight_col + 1, search_end):
        val = row_values[idx]
        if date_col is None and is_date_header(val):
            date_col = idx
        elif ac_col is None and is_ac_header(val):
            ac_col = idx
        elif from_col is None and is_from_header(val):
            from_col = idx
    topic_col = find_complaint_topic_column(row_values, flight_col)
    if topic_col is None:
        return None
    if date_col is None or ac_col is None or from_col is None:
        # Reject summary/pivot sections that only happen to contain something like Flight.
        return None
    topic_name = row_values[topic_col]
    if not is_valid_complaint_topic_header(topic_name):
        return None
    return {"flight_col": flight_col, "date_col": date_col, "ac_col": ac_col, "from_col": from_col, "topic_col": topic_col}


def extract_complaint_sheet(raw_sheet: pd.DataFrame, sheet_name: str, source_file: Path, default_month: Optional[str]) -> pd.DataFrame:
    records: List[Dict[str, object]] = []
    if raw_sheet.empty:
        return pd.DataFrame(columns=COMPLAINT_OUTPUT_COLUMNS + ["Month", "Source File", "Source Sheet"])

    sheet_main_topic = infer_complaint_main_topic(sheet_name)
    raw_sheet = raw_sheet.copy()
    header_rows: List[Tuple[int, Dict[str, int], str, str]] = []

    for row_idx in range(len(raw_sheet)):
        row_values = raw_sheet.iloc[row_idx].tolist()
        for col_idx, value in enumerate(row_values):
            if not is_flight_header(value):
                continue
            block = detect_complaint_block(row_values, col_idx)
            if block is None:
                continue
            raw_topic_name = clean_text(row_values[block["topic_col"]])
            if not is_valid_complaint_topic_header(raw_topic_name):
                continue
            mapped_main, mapped_topic = map_complaint_topic(sheet_main_topic, raw_topic_name)
            if not mapped_topic:
                continue
            header_rows.append((row_idx, block, mapped_main, mapped_topic))

    # De-duplicate repeated header rows that can occur due to merged visual sections.
    seen_headers = set()
    unique_headers = []
    for header_idx, block, mapped_main, mapped_topic in header_rows:
        header_key = (header_idx, block["flight_col"], block["topic_col"], mapped_main, mapped_topic)
        if header_key not in seen_headers:
            seen_headers.add(header_key)
            unique_headers.append((header_idx, block, mapped_main, mapped_topic))

    for header_idx, block, mapped_main, mapped_topic in unique_headers:
        for data_idx in range(header_idx + 1, len(raw_sheet)):
            row_values = raw_sheet.iloc[data_idx].tolist()
            if block["flight_col"] < len(row_values) and is_flight_header(row_values[block["flight_col"]]):
                break
            flight_value = row_values[block["flight_col"]] if block["flight_col"] < len(row_values) else None
            if not looks_like_flight(flight_value):
                continue
            comment_value = row_values[block["topic_col"]] if block["topic_col"] < len(row_values) else None
            comment_text = clean_text(comment_value)
            if len(comment_text) < 2 or is_metadata_header(comment_text) or is_numeric_like(comment_text):
                continue
            date_value = row_values[block["date_col"]] if block["date_col"] < len(row_values) else None
            date_parsed = parse_excel_date(date_value)
            if pd.isna(date_parsed):
                # Skip rows where the supposed date cell is not a valid TCSS date.
                continue
            month_value = pd.to_datetime(date_parsed).strftime("%Y-%m") if pd.notna(date_parsed) else default_month
            ac_value = row_values[block["ac_col"]] if block["ac_col"] < len(row_values) else ""
            from_value = row_values[block["from_col"]] if block["from_col"] < len(row_values) else ""
            from_text = clean_text(from_value)
            if not from_text or is_numeric_like(from_text):
                continue
            records.append({
                "Main Topic": mapped_main,
                "Topic": mapped_topic,
                "FLIGHT": clean_flight_no(flight_value),
                "DATE": date_parsed.to_pydatetime() if pd.notna(date_parsed) else None,
                "A/C TYPE": clean_text(ac_value),
                "FROM": from_text,
                "comment (text)": comment_text,
                "Month": month_value,
                "Source File": source_file.name,
                "Source Sheet": sheet_name,
            })

    out = pd.DataFrame(records)
    if out.empty:
        return pd.DataFrame(columns=COMPLAINT_OUTPUT_COLUMNS + ["Month", "Source File", "Source Sheet"])
    out = out.drop_duplicates(["Main Topic", "Topic", "FLIGHT", "DATE", "comment (text)"], keep="first")
    return out.reset_index(drop=True)


def validate_complaint_detail(detail_df: pd.DataFrame) -> pd.DataFrame:
    checks = []
    total_rows = len(detail_df)
    checks.append({"Check": "Total extracted rows", "Result": total_rows, "Status": "OK" if total_rows > 0 else "Warning"})
    required = COMPLAINT_OUTPUT_COLUMNS + ["Month", "Source File", "Source Sheet"]
    for col in required:
        missing = int(detail_df[col].isna().sum()) if col in detail_df.columns else total_rows
        blank = int((detail_df[col].astype(str).str.strip() == "").sum()) if col in detail_df.columns else total_rows
        checks.append({"Check": f"Missing / blank {col}", "Result": missing + blank, "Status": "OK" if missing + blank == 0 else "Review"})
    if not detail_df.empty and set(["Main Topic", "Topic", "FLIGHT", "DATE", "comment (text)"]).issubset(detail_df.columns):
        duplicate_count = int(detail_df.duplicated(["Main Topic", "Topic", "FLIGHT", "DATE", "comment (text)"]).sum())
    else:
        duplicate_count = 0
    checks.append({"Check": "Duplicate complaint records", "Result": duplicate_count, "Status": "OK" if duplicate_count == 0 else "Review"})
    if not detail_df.empty and "Main Topic" in detail_df.columns:
        unknown_topics = sorted(set(detail_df["Main Topic"].astype(str)) - set(COMPLAINT_MAIN_TOPIC_ORDER))
        checks.append({"Check": "Unmapped main topics", "Result": ", ".join(unknown_topics) if unknown_topics else "None", "Status": "Review" if unknown_topics else "OK"})
    checks.append({"Check": "Parser Version", "Result": COMPLAINT_PARSER_VERSION, "Status": "OK"})
    return pd.DataFrame(checks)


def build_summary_complaint_from_raw_folder(raw_folder: str, output_file: str = COMPLAINT_DETAIL_OUTPUT_DEFAULT) -> Tuple[pd.DataFrame, pd.DataFrame, Path]:
    raw_path = Path(raw_folder).expanduser()
    if not raw_path.is_absolute():
        app_dir = Path(__file__).resolve().parent
        app_candidate = app_dir / raw_path
        cwd_candidate = Path.cwd() / raw_path
        raw_path = app_candidate if app_candidate.exists() else cwd_candidate
    if not raw_path.exists() or not raw_path.is_dir():
        raise FileNotFoundError(f"Raw complaint folder not found: {raw_path}")

    files = sorted(list(raw_path.glob("*.xlsx")) + list(raw_path.glob("*.xlsm")) + list(raw_path.glob("*.xls")))
    files = [f for f in files if not f.name.startswith("~$") and "summary complaint detail" not in f.name.lower()]
    if not files:
        raise FileNotFoundError(f"No Excel complaint files found in: {raw_path}")

    frames = []
    errors = []
    for file_path in files:
        try:
            part = extract_complaint_workbook(file_path)
            if not part.empty:
                frames.append(part)
        except Exception as exc:
            errors.append({"File": file_path.name, "Error": str(exc)})

    detail = pd.concat(frames, ignore_index=True) if frames else pd.DataFrame(columns=COMPLAINT_OUTPUT_COLUMNS + ["Month", "Source File", "Source Sheet"])
    if not detail.empty:
        for col in COMPLAINT_OUTPUT_COLUMNS + ["Month", "Source File", "Source Sheet"]:
            if col not in detail.columns:
                detail[col] = ""
        detail["DATE"] = pd.to_datetime(detail["DATE"], errors="coerce")
        fallback_month = detail["Month"].astype(str).str.slice(0, 7)
        detail["Month"] = detail["DATE"].dt.strftime("%Y-%m").fillna(fallback_month)
        detail["FLIGHT"] = detail["FLIGHT"].apply(clean_flight_no)
        detail["FROM"] = detail["FROM"].apply(clean_text)
        detail["comment (text)"] = detail["comment (text)"].apply(clean_text)
        detail = detail[
            (detail["FLIGHT"] != "") &
            (detail["FROM"] != "") &
            (detail["comment (text)"] != "") &
            (detail["DATE"].notna())
        ].copy()
        detail = detail.drop_duplicates(["Main Topic", "Topic", "FLIGHT", "DATE", "comment (text)"], keep="first")
        detail["Main Topic"] = pd.Categorical(detail["Main Topic"], categories=COMPLAINT_MAIN_TOPIC_ORDER, ordered=True)
        detail = detail.sort_values(["Month", "Main Topic", "Topic", "FLIGHT"], na_position="last")
        detail["Main Topic"] = detail["Main Topic"].astype(str)

    validation_df = validate_complaint_detail(detail)
    if errors:
        validation_df = pd.concat(
            [validation_df, pd.DataFrame([{"Check": f"File error: {x['File']}", "Result": x["Error"], "Status": "Warning"} for x in errors])],
            ignore_index=True,
        )

    summary_for_trend = pd.DataFrame(columns=["TCSS Topic", "Complaint Topic"])
    if not detail.empty:
        trend = detail.copy()
        trend["Month Label"] = pd.to_datetime(trend["Month"] + "-01", errors="coerce").dt.strftime("%b %Y")
        summary_for_trend = (
            trend.groupby(["Main Topic", "Topic", "Month Label"], as_index=False)
            .size()
            .rename(columns={"size": "Count"})
            .pivot_table(index=["Main Topic", "Topic"], columns="Month Label", values="Count", aggfunc="sum", fill_value=0)
            .reset_index()
            .rename(columns={"Main Topic": "TCSS Topic", "Topic": "Complaint Topic"})
        )

    output_path = Path(output_file).expanduser()
    if not output_path.is_absolute():
        output_path = Path(__file__).resolve().parent / output_path

    existing_commendation = None
    summary_complaint_path = get_data_file_path("Summary Complaint.xlsx")
    for source_path in [output_path, summary_complaint_path]:
        if source_path is None or not Path(source_path).exists():
            continue
        try:
            existing_commendation = pd.read_excel(source_path, sheet_name="Commendation", engine="openpyxl")
            if existing_commendation is not None and not existing_commendation.empty:
                break
        except Exception:
            continue

    with pd.ExcelWriter(output_path, engine="openpyxl", mode="w") as writer:
        summary_for_trend.to_excel(writer, index=False, sheet_name="Summary")
        detail[COMPLAINT_OUTPUT_COLUMNS + ["Month", "Source File", "Source Sheet"]].to_excel(writer, index=False, sheet_name="Complaint Detail")
        validation_df.to_excel(writer, index=False, sheet_name="Data Quality")
        if existing_commendation is not None and not existing_commendation.empty:
            existing_commendation.to_excel(writer, index=False, sheet_name="Commendation")
    return detail, validation_df, output_path



def complaint_detail_has_current_parser_version(output_path: Path) -> bool:
    if not output_path.exists():
        return False
    try:
        dq = pd.read_excel(output_path, sheet_name="Data Quality", engine="openpyxl")
        if {"Check", "Result"}.issubset(dq.columns):
            version_rows = dq[dq["Check"].astype(str).str.strip().str.lower() == "parser version"]
            if not version_rows.empty:
                return str(version_rows["Result"].iloc[0]).strip() == COMPLAINT_PARSER_VERSION
    except Exception:
        return False
    return False


def complaint_detail_looks_corrupt(output_path: Path) -> bool:
    """Detect old parser output such as 1970 dates or numeric-only topics."""
    if not output_path.exists():
        return True
    try:
        sample = pd.read_excel(output_path, sheet_name="Complaint Detail", nrows=500, engine="openpyxl")
    except Exception:
        return True
    if sample.empty:
        return True
    cols = {clean_text(c): c for c in sample.columns}
    topic_col = cols.get("Topic")
    date_col = cols.get("DATE")
    if topic_col and sample[topic_col].astype(str).str.fullmatch(r"\d+").any():
        return True
    if date_col:
        dates = pd.to_datetime(sample[date_col], errors="coerce")
        if dates.dropna().dt.year.lt(2000).any():
            return True
    return False


def ensure_summary_complaint_detail_file(
    raw_folder: str = COMPLAINT_RAW_FOLDER_DEFAULT,
    output_file: str = COMPLAINT_DETAIL_OUTPUT_DEFAULT,
) -> Tuple[Optional[Path], Optional[str]]:
    """Auto-build Summary Complaint Detail.xlsx from Complaint_Raw with parser-version control."""
    raw_path = resolve_complaint_raw_folder(raw_folder)
    output_path = Path(__file__).resolve().parent / output_file

    if raw_path is None:
        return (output_path if output_path.exists() else None), None

    raw_files = sorted([p for p in list(raw_path.glob("*.xlsx")) + list(raw_path.glob("*.xlsm")) + list(raw_path.glob("*.xls")) if not p.name.startswith("~$")])
    if not raw_files:
        return (output_path if output_path.exists() else None), f"Complaint_Raw folder found but no Excel files are available: {raw_path}"

    try:
        output_is_current = output_path.exists() and output_path.stat().st_mtime >= newest_mtime(raw_files)
        parser_is_current = complaint_detail_has_current_parser_version(output_path)
        output_is_clean = not complaint_detail_looks_corrupt(output_path)
        if (not output_is_current) or (not parser_is_current) or (not output_is_clean):
            detail, validation, built_path = build_summary_complaint_from_raw_folder(str(raw_path), str(output_path))
            status_msg = f"Created {built_path.name} from {len(raw_files):,} raw complaint files with {len(detail):,} rows."
            return built_path, status_msg
        return output_path, None
    except Exception as exc:
        return (output_path if output_path.exists() else None), f"Cannot auto-build {output_file}: {exc}"

