def _sync_year_month_selection(year: int, month_values: List[str]) -> None:
    """Synchronize child month checkbox states with a Select-all year checkbox."""
    all_key = f"time_all_{year}_{VIEW_MODE}"
    is_checked = bool(st.session_state.get(all_key, False))
    for month_value in month_values:
        st.session_state[f"time_month_{month_value}_{VIEW_MODE}"] = is_checked


def render_time_tree(container, available_month_df: pd.DataFrame, defaults: List[str]) -> List[str]:
    """Render year/month selector with reliable expander and Select-all behavior.

    Fixes two UI issues:
    1) Select all now visually checks every child month checkbox.
    2) Widgets are rendered through the expander object, so child months collapse
       correctly when the year header is collapsed.
    """
    selected: List[str] = []
    temp = available_month_df.copy().sort_values(["Year", "MonthNum"])

    container.markdown("### Time")
    for year in sorted(temp["Year"].dropna().astype(int).unique().tolist()):
        year_part = temp[temp["Year"] == year].sort_values("MonthNum")
        month_values = year_part["Month"].astype(str).tolist()
        exp = container.expander(str(year), expanded=(year == int(temp["Year"].max())))
        all_key = f"time_all_{year}_{VIEW_MODE}"
        if all_key not in st.session_state:
            st.session_state[all_key] = False

        all_checked = exp.checkbox(
            f"Select all {year}",
            key=all_key,
            on_change=_sync_year_month_selection,
            args=(year, month_values),
        )

        # Defensive synchronization for reruns and older Streamlit versions.
        if all_checked:
            for month_value in month_values:
                st.session_state[f"time_month_{month_value}_{VIEW_MODE}"] = True

        for _, row in year_part.iterrows():
            month_value = str(row["Month"])
            month_name = row["MonthName"]
            month_key = f"time_month_{month_value}_{VIEW_MODE}"
            default_checked = month_value in defaults
            if month_key not in st.session_state:
                st.session_state[month_key] = bool(default_checked)

            checked = exp.checkbox(
                str(month_name),
                key=month_key,
                disabled=all_checked,
            )
            if all_checked or checked:
                selected.append(month_value)

    return sorted(set(selected), key=lambda x: pd.to_datetime(str(x) + "-01", errors="coerce"))


