def scroll_to_top_when_touchpoint_changes(touchpoint_name: str) -> None:
    """Force the dashboard to start from the top after every touchpoint change.

    Streamlit can preserve scroll position across reruns. V13 combines a radio
    on_change flag with a stronger parent-window script and repeated attempts so
    the visible dashboard reliably returns to the top after a new touchpoint is selected.
    """
    key = f"{VIEW_MODE}:{touchpoint_name}"
    force_scroll = bool(st.session_state.pop("_tcss_force_scroll_to_top", False))
    last_key = st.session_state.get("_tcss_last_touchpoint_v13")
    if (not force_scroll) and last_key == key:
        return

    st.session_state["_tcss_last_touchpoint_v13"] = key
    components.html(
        """
        <script>
        (function () {
          const scrollTopNow = () => {
            try {
              const parentWindow = window.parent || window;
              const parentDoc = parentWindow.document || document;

              parentWindow.scrollTo(0, 0);
              if (parentDoc.documentElement) parentDoc.documentElement.scrollTop = 0;
              if (parentDoc.body) parentDoc.body.scrollTop = 0;

              const selectors = [
                '[data-testid="stAppViewContainer"]',
                '[data-testid="stMain"]',
                '[data-testid="stMainBlockContainer"]',
                '.main',
                'section.main',
                '.block-container'
              ];
              selectors.forEach((selector) => {
                parentDoc.querySelectorAll(selector).forEach((el) => {
                  if (el && typeof el.scrollTo === 'function') el.scrollTo(0, 0);
                  if (el) el.scrollTop = 0;
                });
              });

              // Catch any Streamlit-managed scroll containers.
              parentDoc.querySelectorAll('*').forEach((el) => {
                try {
                  if (el.scrollTop && el.scrollTop > 0) el.scrollTop = 0;
                } catch (error) {}
              });

              const anchor = parentDoc.getElementById('tcss-top');
              if (anchor && typeof anchor.scrollIntoView === 'function') {
                anchor.scrollIntoView({ behavior: 'auto', block: 'start' });
              }
            } catch (error) {}
          };

          scrollTopNow();
          [25, 80, 180, 360, 720, 1200, 1800].forEach((delay) => {
            setTimeout(scrollTopNow, delay);
          });
        })();
        </script>
        """,
        height=1,
        width=1,
    )


