def normalize_station_key(value: object) -> str:
    return re.sub(r"[^A-Z0-9]+", "", clean_text(value).upper())


def resolve_station_coordinate(station_value: object) -> Tuple[str, Optional[float], Optional[float], Optional[str]]:
    station_text = clean_text(station_value)
    if not station_text:
        return "", None, None, None
    station_key = normalize_station_key(station_text)
    coord_df = pd.DataFrame(STATION_COORDINATES)
    if coord_df.empty:
        return station_text, None, None, None
    coord_df["Station Key"] = coord_df["Station"].apply(normalize_station_key)
    exact = coord_df[coord_df["Station Key"] == station_key]
    if exact.empty:
        # Partial/fuzzy match for spelling variants such as UbonRatchathani / Ubon Ratchathani.
        partial = coord_df[
            coord_df["Station Key"].apply(lambda x: station_key in x or x in station_key if station_key and x else False)
        ]
        exact = partial.head(1)
    if exact.empty:
        scored = []
        for _, row in coord_df.iterrows():
            score = SequenceMatcher(None, station_key, row["Station Key"]).ratio()
            if score >= 0.78:
                scored.append((score, row))
        if scored:
            scored.sort(key=lambda x: x[0], reverse=True)
            row = scored[0][1]
            country = STATION_COUNTRY_BY_KEY.get(row["Station Key"])
            return clean_text(row["Station"]), float(row["Latitude"]), float(row["Longitude"]), country
        return station_text, None, None, None
    row = exact.iloc[0]
    country = STATION_COUNTRY_BY_KEY.get(row["Station Key"])
    return clean_text(row["Station"]), float(row["Latitude"]), float(row["Longitude"]), country


def render_complaint_station_heatmap(topics: List[str], title: str = "Complaint by Station"):
    """Render station-level complaint intensity using FROM from Summary Complaint Detail.xlsx."""
    if complaint_detail_df.empty:
        return
    required_cols = {"Topic Canonical", "Month", "FROM", "Topic", "comment (text)"}
    if not required_cols.issubset(set(complaint_detail_df.columns)):
        st.warning("Complaint detail data is available, but required columns are missing for station heatmap.")
        return

    work = complaint_detail_df.copy()
    work = work[(work["Topic Canonical"].isin(topics)) & (work["Month"].isin(selected_months))].copy()
    if "Topic" in work.columns:
        work = work[~work["Topic"].astype(str).str.contains("commendation", case=False, na=False)].copy()
    work = work[(work["FROM"].astype(str).str.strip() != "") & (work["comment (text)"].astype(str).str.strip() != "")].copy()
    if work.empty:
        return

    resolved = work["FROM"].apply(resolve_station_coordinate)
    work["Station Mapped"] = resolved.apply(lambda x: x[0])
    work["Latitude"] = resolved.apply(lambda x: x[1])
    work["Longitude"] = resolved.apply(lambda x: x[2])
    work["Country"] = resolved.apply(lambda x: x[3])
    mapped = work.dropna(subset=["Latitude", "Longitude"]).copy()
    if mapped.empty:
        st.info("No station coordinate mapping found for the selected complaint records.")
        return

    station_counts = (
        mapped.groupby(["Station Mapped", "Country", "Latitude", "Longitude"], dropna=False, as_index=False)
        .size()
        .rename(columns={"size": "Complaint Count"})
        .sort_values("Complaint Count", ascending=False)
    )
    max_count = max(1, int(station_counts["Complaint Count"].max()))
    station_counts["Marker Size"] = station_counts["Complaint Count"].apply(lambda x: 7 + 18 * (float(x) / max_count) ** 0.55)

    country_counts = (
        station_counts.dropna(subset=["Country"])
        .groupby("Country", as_index=False)["Complaint Count"]
        .sum()
        .sort_values("Complaint Count", ascending=False)
    )
    country_counts["ISO3"] = country_counts["Country"].apply(country_to_iso3)
    country_counts = country_counts.dropna(subset=["ISO3"])

    fig = go.Figure()

    # Country-level choropleth creates a true world heatmap, while station markers
    # keep the underlying FROM station detail available for operational drill-down.
    if not country_counts.empty:
        fig.add_trace(
            go.Choropleth(
                locations=country_counts["ISO3"],
                z=country_counts["Complaint Count"],
                text=country_counts["Country"],
                colorscale=[
                    [0.00, "#FFF6CC"],
                    [0.18, "#F5C300"],
                    [0.42, "#F08A00"],
                    [0.68, "#B6007D"],
                    [1.00, "#370E62"],
                ],
                zmin=0,
                zmax=max(1, float(country_counts["Complaint Count"].max())),
                marker_line_color="#FFFFFF",
                marker_line_width=0.65,
                colorbar=dict(
                    title=dict(text="Complaints", font=dict(size=11, color=TEXT_MAIN)),
                    thickness=13,
                    len=0.68,
                    tickfont=dict(size=10, color=TEXT_MAIN),
                    outlinewidth=0,
                ),
                hovertemplate="<b>%{text}</b><br>Complaints: %{z:,.0f}<extra></extra>",
                name="Country heatmap",
            )
        )

    fig.add_trace(
        go.Scattergeo(
            lon=station_counts["Longitude"],
            lat=station_counts["Latitude"],
            text=station_counts["Station Mapped"],
            mode="markers",
            marker=dict(
                size=station_counts["Marker Size"],
                color=station_counts["Complaint Count"],
                colorscale=[
                    [0.00, "#F5C300"],
                    [0.40, "#F08A00"],
                    [0.72, "#B6007D"],
                    [1.00, "#370E62"],
                ],
                cmin=0,
                cmax=max(1, float(station_counts["Complaint Count"].max())),
                line=dict(width=1.35, color="#FFFFFF"),
                opacity=0.92,
                showscale=False,
            ),
            customdata=station_counts[["Country", "Complaint Count"]],
            hovertemplate="<b>%{text}</b><br>Country: %{customdata[0]}<br>Complaints: %{customdata[1]:,.0f}<extra></extra>",
            name="Station",
            showlegend=False,
        )
    )
    fig.update_layout(
        title=title,
        geo=dict(
            scope="world",
            projection_type="natural earth",
            showland=True,
            landcolor="#F4F0FA",
            showocean=True,
            oceancolor="#EEF5FF",
            showlakes=True,
            lakecolor="#EEF5FF",
            showcountries=True,
            countrycolor="#CBD5E1",
            coastlinecolor="#D8DEE9",
            showframe=False,
            lataxis_showgrid=False,
            lonaxis_showgrid=False,
            center=dict(lat=12, lon=78),
            projection_scale=1.18,
        ),
        margin=dict(l=10, r=10, t=76, b=20),
    )
    apply_plot_layout(fig, height=430 if not IS_MOBILE_MODE else 360, title_size=18, show_grid=False)

    if not IS_MOBILE_MODE and not station_counts.empty:
        map_col, station_col = st.columns([3.75, 1.0], gap="medium")
        with map_col:
            render_plotly_chart(fig, enable_scroll_zoom=True)
        with station_col:
            st.markdown("<div class='table-caption-note'>Number Complaints by Station</div>", unsafe_allow_html=True)
            station_display = station_counts[["Station Mapped", "Complaint Count"]].sort_values("Complaint Count", ascending=False).head(18).copy()
            station_display = station_display.rename(columns={"Station Mapped": "Station"})
            dataframe_white(station_display, height=430)
    else:
        render_plotly_chart(fig, enable_scroll_zoom=True)

    with st.expander("View station complaint records behind the heatmap", expanded=False):
        detail_cols = ["Main Topic", "Topic", "FLIGHT", "DATE", "A/C TYPE", "FROM", "comment (text)"]
        display = work[detail_cols].copy()
        display["DATE"] = pd.to_datetime(display["DATE"], errors="coerce").dt.strftime("%Y-%m-%d")
        dataframe_white(display, height=300)

def render_complaint_flight_heatmap(topics: List[str], title: str = "Complaint by Flight"):
    """Render flight-level complaint intensity for the selected period and touchpoint(s)."""
    if complaint_detail_df.empty:
        return
    required_cols = {"Topic Canonical", "Month", "FLIGHT", "Topic", "comment (text)"}
    if not required_cols.issubset(set(complaint_detail_df.columns)):
        st.warning("Complaint detail data is available, but required columns are missing for flight heatmap.")
        return

    work = complaint_detail_df.copy()
    work = work[(work["Topic Canonical"].isin(topics)) & (work["Month"].isin(selected_months))].copy()
    if "Topic" in work.columns:
        work = work[~work["Topic"].astype(str).str.contains("commendation", case=False, na=False)].copy()
    work = work[(work["FLIGHT"].astype(str).str.strip() != "") & (work["comment (text)"].astype(str).str.strip() != "")].copy()
    if work.empty:
        return

    # Keep the heatmap executive-readable: focus on flights with the highest complaint intensity.
    top_n = 18 if not IS_MOBILE_MODE else 10
    top_flights = (
        work.groupby("FLIGHT", as_index=False)
        .size()
        .rename(columns={"size": "Complaint Count"})
        .sort_values("Complaint Count", ascending=False)
        .head(top_n)["FLIGHT"].tolist()
    )
    work = work[work["FLIGHT"].isin(top_flights)].copy()
    month_order = sorted(work["Month"].dropna().unique().tolist(), key=lambda x: pd.to_datetime(str(x) + "-01", errors="coerce"))
    flight_order = (
        work.groupby("FLIGHT")
        .size()
        .sort_values(ascending=True)
        .index.tolist()
    )
    matrix = (
        work.groupby(["FLIGHT", "Month"], as_index=False)
        .size()
        .rename(columns={"size": "Complaint Count"})
        .pivot(index="FLIGHT", columns="Month", values="Complaint Count")
        .reindex(index=flight_order, columns=month_order)
        .fillna(0)
    )
    if matrix.empty:
        return

    month_labels = [pd.to_datetime(m + "-01", errors="coerce").strftime("%b %Y") if pd.notna(pd.to_datetime(m + "-01", errors="coerce")) else m for m in month_order]
    fig = go.Figure(
        data=go.Heatmap(
            z=matrix.values,
            x=month_labels,
            y=matrix.index.tolist(),
            colorscale=[[0, "#FFFFFF"], [0.25, THAI_GOLD_SOFT], [0.65, DASHING_YELLOW], [1, FLAMBOYANT_PINK]],
            colorbar=dict(title="Count", thickness=10, len=0.72, tickfont=dict(size=9)),
            hovertemplate="<b>Flight %{y}</b><br>Month: %{x}<br>Complaints: %{z:,.0f}<extra></extra>",
        )
    )
    fig.update_traces(text=matrix.values, texttemplate="%{text:.0f}", textfont={"size": 10, "color": TEXT_MAIN})
    fig.update_layout(
        title=title,
        xaxis_title="Selected Month",
        yaxis_title="Flight",
        margin=dict(l=100 if not IS_MOBILE_MODE else 74, r=56, t=86, b=54),
    )
    dynamic_height = min(520 if not IS_MOBILE_MODE else 430, max(300 if not IS_MOBILE_MODE else 260, 130 + 24 * max(1, len(matrix.index))))
    apply_plot_layout(fig, height=dynamic_height, title_size=18)
    fig.update_xaxes(side="top", tickangle=0, automargin=True)
    fig.update_yaxes(automargin=True)
    render_plotly_chart(fig)

    with st.expander("View complaint records behind the flight heatmap", expanded=False):
        detail_cols = ["Main Topic", "Topic", "FLIGHT", "DATE", "A/C TYPE", "FROM", "comment (text)"]
        display = work[detail_cols].copy()
        display["DATE"] = pd.to_datetime(display["DATE"], errors="coerce").dt.strftime("%Y-%m-%d")
        dataframe_white(display, height=300)


def render_complaint_trend(topics: List[str], include_commendation: bool, title: str, height: Optional[int] = None):
    comp = get_complaint_working_df(complaint_summary_df, topics)
    if comp.empty:
        st.info("No complaint trend data available.")
        return

    years_available = sorted(comp["Year"].dropna().astype(int).unique().tolist())
    target_years = [y for y in [previous_year, current_year] if y in years_available]
    if not target_years:
        target_years = years_available[-2:] if len(years_available) >= 2 else years_available

    metric_df = monthly_metric_grid(comp, target_years, include_commendation=include_commendation)
    if metric_df.empty:
        st.info("No complaint trend data available.")
        return

    color_map = {
        f"Complaint {target_years[0] if target_years else ''}": DASHING_YELLOW,
        f"Complaint {target_years[-1] if target_years else ''}": FLAMBOYANT_PINK,
        f"Commendation {target_years[0] if target_years else ''}": "#7ED321",
        f"Commendation {target_years[-1] if target_years else ''}": GREEN_GOOD,
    }

    fig = px.line(
        metric_df,
        x="MonthName",
        y="Complaint Count",
        color="Metric / Year",
        markers=True,
        category_orders={"MonthName": MONTH_ORDER},
        title=title,
        color_discrete_map=color_map,
        hover_data={"Year": True, "Metric": True, "Complaint Count": ":,.0f"},
    )
    for trace in fig.data:
        if target_years and str(target_years[0]) in trace.name:
            trace.update(line=dict(dash="dash", width=2.0), marker=dict(size=7))
        else:
            trace.update(line=dict(dash="solid", width=3.2), marker=dict(size=8))
    chart_height = height if height is not None else (300 if not IS_MOBILE_MODE else 268)
    apply_plot_layout(fig, height=chart_height + (18 if not IS_MOBILE_MODE else 12), title_size=17)
    fig.update_layout(
        xaxis_title="Month",
        yaxis_title="Count",
        hovermode="x unified",
        margin=dict(l=50, r=36, t=106 if not IS_MOBILE_MODE else 94, b=58),
    )
    apply_safe_top_legend(fig, y=1.11, title="Metric / Year")
    fig.update_xaxes(categoryorder="array", categoryarray=MONTH_ORDER)
    render_plotly_chart(fig)


